sql:
SELECT type_name, description, created_at, updated_at
FROM command_types
ORDER BY type_id DESC;

external_knowledge:
- 'wise guardians' refers to users who have performed audit actions;
- 'mark of their deeds' refers to audit actions such as 'executed', 'reviewed', or 'approved';
- 'more than one mark' indicates that the user has performed these actions more than once.

